const original = $('Decide AI mode').first().json;
const getFile = $('Telegram getFile').first().json;

const item = $input.first();
const binaryMeta = item.binary?.data;

if (!binaryMeta) {
  return [
    {
      json: {
        ...original,
        file_analysis_status: 'failed',
        file_analysis_text: 'File was received, but binary metadata was not available for AI analysis.',
        file_analysis_json: {
          summary: null,
          detected_type: original.message_type || null,
          language: null,
          visible_or_extracted_text: null,
          keywords: [],
          important_details: [],
          suggested_topics: [],
          confidence: 0,
          error: 'No binary.data metadata found'
        },
        skip_gemini_analysis: true
      }
    }
  ];
}

// IMPORTANT:
// In n8n binary mode, binary.data.data may contain "filesystem-v2..." instead of real base64.
// So we must read the real binary buffer and convert it to base64 ourselves.
let fileBase64;

try {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  fileBase64 = buffer.toString('base64');
} catch (error) {
  return [
    {
      json: {
        ...original,
        file_analysis_status: 'failed',
        file_analysis_text: 'File was received, but n8n could not read the binary buffer for AI analysis.',
        file_analysis_json: {
          summary: null,
          detected_type: original.message_type || null,
          language: null,
          visible_or_extracted_text: null,
          keywords: [],
          important_details: [],
          suggested_topics: [],
          confidence: 0,
          error: error.message
        },
        skip_gemini_analysis: true
      }
    }
  ];
}

const messageType = String(original.message_type || 'document').toLowerCase();

function detectMimeType(messageType, original, binaryMeta, getFile) {
  const fileName = String(
    original.file_name ||
    binaryMeta?.fileName ||
    getFile?.result?.file_path ||
    ''
  ).toLowerCase();

  const telegramPath = String(getFile?.result?.file_path || '').toLowerCase();

  if (messageType === 'photo') {
    if (fileName.endsWith('.png') || telegramPath.endsWith('.png')) {
      return 'image/png';
    }

    if (fileName.endsWith('.webp') || telegramPath.endsWith('.webp')) {
      return 'image/webp';
    }

    return 'image/jpeg';
  }

  if (messageType === 'voice') {
    return original.mime_type || binaryMeta?.mimeType || 'audio/ogg';
  }

  if (messageType === 'audio') {
    return original.mime_type || binaryMeta?.mimeType || 'audio/mpeg';
  }

  if (messageType === 'video') {
    return original.mime_type || binaryMeta?.mimeType || 'video/mp4';
  }

  if (messageType === 'video_note') {
    return original.mime_type || binaryMeta?.mimeType || 'video/mp4';
  }

  const originalMime = original.mime_type || '';
  const binaryMime = binaryMeta?.mimeType || '';

  const candidateMime =
    originalMime && originalMime !== 'application/octet-stream'
      ? originalMime
      : binaryMime && binaryMime !== 'application/octet-stream'
        ? binaryMime
        : '';

  if (candidateMime) {
    return candidateMime;
  }

  if (fileName.endsWith('.pdf') || telegramPath.endsWith('.pdf')) {
    return 'application/pdf';
  }

  if (
    fileName.endsWith('.jpg') ||
    fileName.endsWith('.jpeg') ||
    telegramPath.endsWith('.jpg') ||
    telegramPath.endsWith('.jpeg')
  ) {
    return 'image/jpeg';
  }

  if (fileName.endsWith('.png') || telegramPath.endsWith('.png')) {
    return 'image/png';
  }

  if (fileName.endsWith('.webp') || telegramPath.endsWith('.webp')) {
    return 'image/webp';
  }

  if (fileName.endsWith('.txt') || telegramPath.endsWith('.txt')) {
    return 'text/plain';
  }

  if (fileName.endsWith('.csv') || telegramPath.endsWith('.csv')) {
    return 'text/csv';
  }

  if (fileName.endsWith('.json') || telegramPath.endsWith('.json')) {
    return 'application/json';
  }

  if (fileName.endsWith('.md') || telegramPath.endsWith('.md')) {
    return 'text/markdown';
  }

  if (fileName.endsWith('.html') || telegramPath.endsWith('.html')) {
    return 'text/html';
  }

  if (fileName.endsWith('.xml') || telegramPath.endsWith('.xml')) {
    return 'application/xml';
  }

  if (fileName.endsWith('.ogg') || telegramPath.endsWith('.ogg')) {
    return messageType === 'video' ? 'video/ogg' : 'audio/ogg';
  }

  if (fileName.endsWith('.mp3') || telegramPath.endsWith('.mp3')) {
    return 'audio/mpeg';
  }

  if (fileName.endsWith('.wav') || telegramPath.endsWith('.wav')) {
    return 'audio/wav';
  }

  if (fileName.endsWith('.m4a') || telegramPath.endsWith('.m4a')) {
    return 'audio/x-m4a';
  }

  if (fileName.endsWith('.mp4') || telegramPath.endsWith('.mp4')) {
    return 'video/mp4';
  }

  if (fileName.endsWith('.webm') || telegramPath.endsWith('.webm')) {
    return 'video/webm';
  }

  if (fileName.endsWith('.mov') || telegramPath.endsWith('.mov')) {
    return 'video/quicktime';
  }

  if (fileName.endsWith('.mkv') || telegramPath.endsWith('.mkv')) {
    return 'video/x-matroska';
  }

  return 'application/octet-stream';
}

const mimeType = detectMimeType(messageType, original, binaryMeta, getFile);

const fileName =
  original.file_name ||
  binaryMeta.fileName ||
  getFile?.result?.file_path ||
  'telegram_file';

const caption = original.caption || '';
const content = original.content || original.message || '';

const supportedMimeTypes = [
  'image/jpeg',
  'image/png',
  'image/webp',
  'image/heic',
  'image/heif',

  'application/pdf',

  'text/plain',
  'text/csv',
  'application/json',
  'text/markdown',
  'text/html',
  'application/xml',
  'text/xml',

  'audio/ogg',
  'audio/mpeg',
  'audio/mp3',
  'audio/wav',
  'audio/webm',
  'audio/mp4',
  'audio/aac',
  'audio/flac',
  'audio/x-wav',
  'audio/x-m4a',
  'application/ogg',

  'video/mp4',
  'video/webm',
  'video/quicktime',
  'video/x-matroska',
  'video/ogg'
];

const isSupported =
  messageType === 'photo' ||
  supportedMimeTypes.includes(mimeType);

if (!isSupported) {
  return [
    {
      json: {
        ...original,
        file_name: fileName,
        mime_type: mimeType,
        telegram_file_path: getFile?.result?.file_path || null,
        file_analysis_status: 'unsupported',
        file_analysis_text:
          `File received but not deeply analyzed. ` +
          `Unsupported MIME type for direct Gemini analysis: ${mimeType}. ` +
          `File name: ${fileName}. ` +
          (caption ? `Caption: ${caption}.` : ''),
        file_analysis_json: {
          summary: null,
          detected_type: messageType,
          language: null,
          visible_or_extracted_text: null,
          keywords: [],
          important_details: [],
          suggested_topics: [],
          confidence: 0.2,
          error: `Unsupported MIME type: ${mimeType}`
        },
        skip_gemini_analysis: true
      }
    }
  ];
}

const prompt = `
You analyze a Telegram message or file for a personal AI memory bot called Memoraq.

Your task is to create a useful AI index for future search.

Return only valid JSON.
Do not use markdown.
Do not wrap the response in code fences.
Do not add explanations outside JSON.

Telegram metadata:
- Message type: ${messageType}
- File name: ${fileName}
- MIME type: ${mimeType}
- Caption: ${caption || '[no caption]'}
- Existing text/content: ${content || '[no text]'}

For photos:
- Describe what is visible.
- Do not identify real people by name.
- If it looks like a receipt, document, product, place, screenshot, certificate, food, travel photo, or work-related image, say so.
- Extract visible text if possible.

For voice and audio messages:
- Transcribe the spoken content if possible.
- Detect the language.
- Summarize the meaning of the voice/audio message.
- Extract names, tasks, dates, places, companies, products, amounts, or important instructions if present.
- Put transcript or useful extracted speech into "visible_or_extracted_text".
- If transcription is not possible, clearly say that the audio could not be transcribed.

For video files:
- Analyze visible content if possible.
- Describe what appears in the video.
- Detect people, objects, places, documents, screens, products, or activities if visible.
- If there is speech or audio, transcribe or summarize it if possible.
- Extract useful searchable keywords.
- Put any useful transcript or visible text into "visible_or_extracted_text".
- If the video cannot be analyzed, clearly say that only metadata was available.

For PDFs and text documents:
- Summarize the main content.
- Extract organizations, dates, amounts, document type, document numbers, and important keywords if present.
- If it looks like a CV/resume, invoice, agreement, bank/tax document, report, sales file, legal document, medical document, or travel document, classify it.

Return exactly this JSON structure:

{
  "summary": "Short useful summary in English, 1-3 sentences",
  "category": "recipe | technical | finance | legal | career | travel | personal | document | photo | shopping | health | task | note | other",
  "detected_type": "photo | voice_message | audio_message | video | video_note | receipt | invoice | contract | resume | report | legal_document | tax_document | bank_document | travel_document | screenshot | product | place | text_document | pdf_document | other",
  "language": "ru | en | he | ar | unknown",
  "keywords": ["keyword1", "keyword2", "keyword3"],
  "entities": ["entity1", "entity2"],
  "important_details": [
    {
      "label": "date | amount | company | person | location | document_number | product | link | other",
      "value": "detail value"
    }
  ],
  "visible_or_extracted_text": "important visible/extracted text or null",
  "confidence": 0.85
}

Rules:
1. Return 5-12 useful keywords.
2. Keywords may include original language words and English/transliterated equivalents.
3. Category must describe the content, not only the Telegram message type.
4. If it is financial, tax, bank, invoice, salary, payment, pension, provident fund, insurance, investment or withdrawal related, use category "finance".
5. If it is a contract, legal letter, rights issue, agreement, claim, court or regulation related, use category "legal".
6. If it is about CV, resume, job search, interview, HR, or career, use category "career".
7. If it is a technical note, code, server, DevOps, n8n, Telegram bot, database, API, automation, or cloud, use category "technical".
8. For video/audio, do not just say "video file" or "audio file" if actual content can be analyzed.
9. Do not suggest, create, or mention topics.
10. Do not return fields named suggested_topics, action, suggested_topic_id, suggested_topic_title, or new_topic_title.
11. Confidence must be a number between 0 and 1.
`.trim();

const requestBody = {
  contents: [
    {
      parts: [
        {
          text: prompt
        },
        {
          inline_data: {
            mime_type: mimeType,
            data: fileBase64
          }
        }
      ]
    }
  ],
  generationConfig: {
    temperature: 0.2,
    responseMimeType: 'application/json'
  }
};

return [
  {
    json: {
      ...original,
      file_name: fileName,
      mime_type: mimeType,
      telegram_file_path: getFile?.result?.file_path || null,
      gemini_request_body: requestBody,
      skip_gemini_analysis: false
    }
  }
];

const input = $input.first().json;

function cleanString(value, maxLength = 500) {
  return String(value || '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, maxLength);
}

const fileName = cleanString(input.file_name || 'telegram_file', 120);
const mimeType = cleanString(input.mime_type || 'unknown mime type', 80);

const summary =
  input.ai_summary ||
  `File saved but not deeply analyzed. Unsupported MIME type for direct Gemini analysis: ${mimeType}.`;

const category = input.message_type === 'photo' ? 'photo' : 'document';

const keywords = [
  'file',
  'unsupported file',
  fileName,
  mimeType,
  category
]
  .map(v => cleanString(v, 80))
  .filter(Boolean);

const importantDetails = [
  {
    label: 'other',
    value: `Unsupported MIME type: ${mimeType}`
  }
];

const aiContent = [
  `Source mode: unsupported_file`,
  `Message type: ${input.message_type || ''}`,
  `File name: ${fileName}`,
  `MIME type: ${mimeType}`,
  `Summary: ${summary}`,
  `Category: ${category}`,
  `Keywords: ${keywords.join(', ')}`
].join('\n');

const clean = {
  ...input,

  message_for_ai: aiContent,

  ai_summary: summary,
  ai_category: category,
  ai_language: 'unknown',
  ai_keywords: keywords,
  ai_entities: [],
  ai_important_details: importantDetails,
  ai_confidence: 0.2,

  ai_raw_json: {
    summary,
    category,
    language: 'unknown',
    keywords,
    entities: [],
    important_details: importantDetails,
    detected_type: input.message_type || 'file',
    mime_type: mimeType,
    file_name: fileName,
    source: 'unsupported_file'
  },

  ai_raw_text: aiContent
};

delete clean.gemini_request_body;
delete clean.skip_gemini_analysis;

return [
  {
    json: clean
  }
];

const original = $('Prepare Gemini file request').first().json;
const response = $input.first().json;

let raw = '';

try {
  raw =
    response.candidates?.[0]?.content?.parts
      ?.map(part => part.text || '')
      .join('\n')
      .trim() || '';
} catch (e) {
  raw = '';
}

raw = String(raw || '')
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  const match = raw.match(/\{[\s\S]*\}/);

  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (e2) {
      parsed = null;
    }
  }

  if (!parsed) {
    parsed = {
      summary: raw || 'The file was analyzed, but the AI response could not be parsed as JSON.',
      category: original.message_type === 'photo' ? 'photo' : 'document',
      detected_type: original.message_type || 'other',
      language: 'unknown',
      keywords: [],
      entities: [],
      important_details: [],
      visible_or_extracted_text: null,
      confidence: 0.3,
      parse_error: e.message
    };
  }
}

function cleanString(value, maxLength = 500) {
  return String(value || '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, maxLength);
}

function cleanArray(value, limit = 12) {
  if (!Array.isArray(value)) return [];

  const seen = new Set();

  return value
    .map(v => cleanString(v, 80))
    .filter(Boolean)
    .filter(v => {
      const key = v.toLowerCase();
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .slice(0, limit);
}

function mapDetectedTypeToCategory(detectedType, messageType) {
  const t = String(detectedType || '').toLowerCase();

  if (['receipt', 'invoice', 'tax_document', 'bank_document'].includes(t)) {
    return 'finance';
  }

  if (['contract', 'legal_document'].includes(t)) {
    return 'legal';
  }

  if (['resume', 'cv'].includes(t)) {
    return 'career';
  }

  if (['travel_document', 'place'].includes(t)) {
    return 'travel';
  }

  if (['product'].includes(t)) {
    return 'shopping';
  }

  if (['photo', 'screenshot'].includes(t)) {
    return 'photo';
  }

  if (['pdf_document', 'text_document', 'report'].includes(t)) {
    return 'document';
  }

  if (messageType === 'photo') {
    return 'photo';
  }

  if (messageType === 'document') {
    return 'document';
  }

  return 'other';
}

const detectedType = cleanString(
  parsed.detected_type ||
  original.message_type ||
  'other',
  50
);

let category = cleanString(parsed.category || '', 40).toLowerCase();

const allowedCategories = [
  'recipe',
  'technical',
  'finance',
  'legal',
  'career',
  'travel',
  'personal',
  'document',
  'photo',
  'shopping',
  'health',
  'task',
  'note',
  'other'
];

if (!allowedCategories.includes(category)) {
  category = mapDetectedTypeToCategory(detectedType, original.message_type);
}

let summary = cleanString(parsed.summary, 260);

if (!summary) {
  summary = original.message_type === 'photo'
    ? 'Photo saved with AI-generated searchable details.'
    : 'Document saved with AI-generated searchable details.';
}

const language = cleanString(parsed.language || 'unknown', 20).toLowerCase();

let keywords = cleanArray(parsed.keywords, 12);

if (keywords.length === 0) {
  keywords = [
    category,
    detectedType,
    original.file_name,
    original.mime_type
  ]
    .map(v => cleanString(v, 80))
    .filter(Boolean)
    .slice(0, 12);
}

const entities = cleanArray(parsed.entities, 12);

const importantDetails = Array.isArray(parsed.important_details)
  ? parsed.important_details
      .filter(Boolean)
      .map(d => ({
        label: cleanString(d.label || 'other', 50),
        value: cleanString(d.value || '', 200)
      }))
      .filter(d => d.value)
      .slice(0, 12)
  : [];

const extractedText = cleanString(parsed.visible_or_extracted_text || '', 2000);

const confidence = Math.max(0, Math.min(1, Number(parsed.confidence || 0.7)));

const aiContent = [
  `Source mode: file`,
  `Message type: ${original.message_type || ''}`,
  original.file_name ? `File name: ${original.file_name}` : null,
  original.mime_type ? `MIME type: ${original.mime_type}` : null,
  `Detected type: ${detectedType}`,
  `Summary: ${summary}`,
  `Category: ${category}`,
  `Language: ${language}`,
  keywords.length ? `Keywords: ${keywords.join(', ')}` : null,
  entities.length ? `Entities: ${entities.join(', ')}` : null,
  importantDetails.length ? `Important details: ${JSON.stringify(importantDetails)}` : null,
  extractedText ? `Extracted text: ${extractedText}` : null,
  original.caption ? `Caption: ${original.caption}` : null
]
  .filter(Boolean)
  .join('\n');

const clean = {
  ...original,

  file_analysis_status: 'done',

  message_for_ai: aiContent,

  ai_summary: summary,
  ai_category: category,
  ai_language: language,
  ai_keywords: keywords,
  ai_entities: entities,
  ai_important_details: importantDetails,
  ai_confidence: confidence,

  ai_raw_json: {
    summary,
    category,
    language,
    keywords,
    entities,
    important_details: importantDetails,
    detected_type: detectedType,
    visible_or_extracted_text: extractedText || null,
    confidence,
    raw_ai_json: parsed,
    source: 'file'
  },

  ai_raw_text: raw || aiContent
};

delete clean.gemini_request_body;
delete clean.skip_gemini_analysis;

return [
  {
    json: clean
  }
];

const input = $input.first().json || {};

const messageType = String(input.message_type || 'text').toLowerCase();

const fileId =
  input.file_id ||
  input.video_file_id ||
  input.voice_file_id ||
  input.audio_file_id ||
  input.document_file_id ||
  input.photo_file_id ||
  null;

const fileUniqueId =
  input.file_unique_id ||
  input.video_file_unique_id ||
  input.voice_file_unique_id ||
  input.audio_file_unique_id ||
  input.document_file_unique_id ||
  input.photo_file_unique_id ||
  null;

const supportedFileMessageTypes = [
  'photo',
  'document',
  'voice',
  'audio',
  'video',
  'video_note'
];

const shouldAnalyzeFile =
  Boolean(fileId) &&
  supportedFileMessageTypes.includes(messageType);

let aiModeReason = '';

if (!fileId) {
  aiModeReason = `No file_id found for message_type=${messageType}`;
} else if (!supportedFileMessageTypes.includes(messageType)) {
  aiModeReason = `Unsupported message_type=${messageType}`;
} else {
  aiModeReason = `File analysis enabled for message_type=${messageType}`;
}

return [
  {
    json: {
      ...input,

      file_id: fileId,
      file_unique_id: fileUniqueId,

      message_type: messageType,
      should_analyze_file: shouldAnalyzeFile,
      ai_mode: shouldAnalyzeFile ? 'file' : 'text',
      ai_mode_reason: aiModeReason
    }
  }
];

const input = $input.first().json;

const messageType = input.message_type || 'text';

const parts = [];

if (input.ai_prompt_input) {
  parts.push(input.ai_prompt_input);
}

if (input.raw_text) {
  parts.push(`Raw text: ${input.raw_text}`);
}

if (input.content) {
  parts.push(`Content: ${input.content}`);
}

if (input.message) {
  parts.push(`Message: ${input.message}`);
}

if (input.caption) {
  parts.push(`Caption: ${input.caption}`);
}

if (input.file_name) {
  parts.push(`File name: ${input.file_name}`);
}

if (input.mime_type) {
  parts.push(`MIME type: ${input.mime_type}`);
}

if (input.location_title) {
  parts.push(`Location title: ${input.location_title}`);
}

if (input.location_address) {
  parts.push(`Location address: ${input.location_address}`);
}

if (input.maps_url) {
  parts.push(`Map: ${input.maps_url}`);
}

if (parts.length === 0) {
  parts.push(`Message type: ${messageType}`);
}

const messageForAI = parts.join('\n\n');

const prompt = `
You analyze a Telegram message for a personal AI memory bot called Memoraq.

Your task is to create a useful AI index for future search.

Always return only valid JSON.
Do not use markdown.
Do not wrap the response in code fences.
Do not add explanations outside JSON.

User ID:
${input.user_id}

Message content:
${messageForAI}

Return exactly this JSON structure:

{
  "summary": "Short useful summary of the actual message content in English, 1-2 sentences",
  "category": "recipe | technical | finance | legal | career | travel | personal | document | photo | shopping | health | task | note | other",
  "detected_type": "text_message | note | location | link | task | other",
  "language": "ru | en | he | ar | unknown",
  "keywords": ["keyword1", "keyword2", "keyword3"],
  "entities": ["entity1", "entity2"],
  "important_details": [
    {
      "label": "date | amount | company | person | location | document_number | product | link | other",
      "value": "detail value"
    }
  ],
  "visible_or_extracted_text": null,
  "confidence": 0.85
}

Rules:
1. "summary" is mandatory.
2. "summary" must summarize the actual content, not repeat it word-for-word.
3. Return 5-12 useful keywords.
4. Keywords may include English transliteration and original-language words if useful.
5. Category must describe the content, not the Telegram message type.
6. If the message is about installation, code, servers, DevOps, n8n, Telegram bot, databases, APIs, automation, or cloud, use "technical".
7. If the message is about money, taxes, invoices, bank, salary, payments, pension, provident fund, insurance, investment, withdrawal, or bank forms, use "finance".
8. If the message is about contracts, rights, claims, agreements, legal letters, court, regulations, or legal documents, use "legal".
9. If the message is about CV, resume, job search, interview, HR, salary negotiation, or career, use "career".
10. If the message includes a location or map link, use category "travel" or "personal" depending on context.
11. Extract entities such as companies, people, places, products, document numbers, dates, and amounts if present.
12. Do not suggest, create, or mention topics.
13. Do not return fields named action, suggested_topic_id, suggested_topic_title, or new_topic_title.
14. Confidence must be a number between 0 and 1.
`.trim();

const requestBody = {
  contents: [
    {
      parts: [
        {
          text: prompt
        }
      ]
    }
  ],
  generationConfig: {
    temperature: 0.2,
    responseMimeType: 'application/json'
  }
};

return [
  {
    json: {
      ...input,
      message_for_ai: messageForAI,
      gemini_request_body: requestBody,
      ai_source_mode: 'text',
      skip_gemini_analysis: false
    }
  }
];

const source = $input.first().json;
const response = $input.first().json;

let original;

try {
  original = $('Prepare Gemini file request').first().json;
} catch (e) {
  try {
    original = $('Prepare Gemini text request').first().json;
  } catch (e2) {
    original = source;
  }
}

let raw = '';

try {
  raw =
    response.candidates?.[0]?.content?.parts
      ?.map(part => part.text || '')
      .join('\n')
      .trim() || '';
} catch (e) {
  raw = '';
}

raw = String(raw || '')
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  const match = raw.match(/\{[\s\S]*\}/);

  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (e2) {
      parsed = null;
    }
  }

  if (!parsed) {
    parsed = {
      summary: raw || 'The message was analyzed, but the AI response could not be parsed as JSON.',
      category: original.message_type === 'photo' ? 'photo' : 'note',
      detected_type: original.message_type || 'other',
      language: 'unknown',
      keywords: [],
      entities: [],
      important_details: [],
      visible_or_extracted_text: null,
      confidence: 0.3,
      parse_error: e.message
    };
  }
}

function cleanString(value, maxLength = 500) {
  return String(value || '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, maxLength);
}

function cleanArray(value, limit = 12) {
  if (!Array.isArray(value)) return [];

  const seen = new Set();

  return value
    .map(v => cleanString(v, 80))
    .filter(Boolean)
    .filter(v => {
      const key = v.toLowerCase();
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .slice(0, limit);
}

const allowedCategories = [
  'recipe',
  'technical',
  'finance',
  'legal',
  'career',
  'travel',
  'personal',
  'document',
  'photo',
  'shopping',
  'health',
  'task',
  'note',
  'other'
];

let category = cleanString(parsed.category || 'note', 40).toLowerCase();

if (!allowedCategories.includes(category)) {
  category = 'other';
}

const messageText = String(
  original.message_for_ai ||
  original.raw_text ||
  original.content ||
  original.message ||
  ''
).replace(/\s+/g, ' ').trim();

let summary = cleanString(parsed.summary, 260);

const summaryLooksLikeOriginal =
  summary.length > 300 ||
  (
    messageText.length > 0 &&
    summary.length > messageText.length * 0.65
  );

if (!summary || summaryLooksLikeOriginal) {
  if (category === 'technical') {
    summary = 'Technical note with practical implementation details.';
  } else if (category === 'finance') {
    summary = 'Finance-related note with useful details for tracking.';
  } else if (category === 'legal') {
    summary = 'Legal or agreement-related note with important details.';
  } else if (category === 'career') {
    summary = 'Career-related note with professional details.';
  } else if (category === 'recipe') {
    summary = 'Cooking note with ingredients or preparation details.';
  } else if (category === 'photo') {
    summary = 'Photo saved with AI-generated searchable details.';
  } else if (category === 'document') {
    summary = 'Document saved with AI-generated searchable details.';
  } else {
    summary = messageText ? messageText.slice(0, 180) : 'Saved Telegram message.';
  }
}

const language = cleanString(parsed.language || 'unknown', 20).toLowerCase();

let keywords = cleanArray(parsed.keywords, 12);

if (keywords.length === 0) {
  keywords = [
    category,
    parsed.detected_type,
    original.message_type,
    original.file_name,
    original.mime_type
  ]
    .map(v => cleanString(v, 80))
    .filter(Boolean)
    .slice(0, 12);
}

const entities = cleanArray(parsed.entities, 12);

const importantDetails = Array.isArray(parsed.important_details)
  ? parsed.important_details
      .filter(Boolean)
      .map(d => ({
        label: cleanString(d.label || 'other', 50),
        value: cleanString(d.value || '', 200)
      }))
      .filter(d => d.value)
      .slice(0, 12)
  : [];

const detectedType = cleanString(
  parsed.detected_type ||
  original.message_type ||
  'other',
  50
);

const extractedText = cleanString(parsed.visible_or_extracted_text || '', 2000);

const confidence = Math.max(0, Math.min(1, Number(parsed.confidence || 0)));

const aiContent = [
  `Source mode: ${original.ai_source_mode || 'unknown'}`,
  `Message type: ${original.message_type || ''}`,
  original.file_name ? `File name: ${original.file_name}` : null,
  original.mime_type ? `MIME type: ${original.mime_type}` : null,
  `Detected type: ${detectedType}`,
  `Summary: ${summary}`,
  `Category: ${category}`,
  `Language: ${language}`,
  keywords.length ? `Keywords: ${keywords.join(', ')}` : null,
  entities.length ? `Entities: ${entities.join(', ')}` : null,
  importantDetails.length ? `Important details: ${JSON.stringify(importantDetails)}` : null,
  extractedText ? `Extracted text: ${extractedText}` : null,
  original.caption ? `Caption: ${original.caption}` : null,
  original.message_for_ai ? `Message: ${original.message_for_ai}` : null
]
  .filter(Boolean)
  .join('\n');

const clean = {
  ...original,

  message_for_ai: aiContent,

  ai_summary: summary,
  ai_category: category,
  ai_language: language,
  ai_keywords: keywords,
  ai_entities: entities,
  ai_important_details: importantDetails,
  ai_confidence: confidence,

  ai_raw_json: {
    summary,
    category,
    language,
    keywords,
    entities,
    important_details: importantDetails,
    detected_type: detectedType,
    visible_or_extracted_text: extractedText || null,
    confidence,
    raw_ai_json: parsed,
    source: original.ai_source_mode || 'unknown'
  },

  ai_raw_text: raw || aiContent
};

delete clean.gemini_request_body;
delete clean.skip_gemini_analysis;

return [
  {
    json: clean
  }
];

